class PasswordResetViewController: UIViewController {

    private var resetToken: String?
    private let tokenLabel = UILabel()
    private let instructionsLabel = UILabel()

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemTeal
        navigationItem.title = "Reset Password"
        setupUI()
        displayToken()
    }

    private func setupUI() {
        instructionsLabel.text = "Enter your new password below."
        instructionsLabel.textAlignment = .center
        instructionsLabel.numberOfLines = 0
        instructionsLabel.font = .systemFont(ofSize: 18)

        tokenLabel.textAlignment = .center
        tokenLabel.numberOfLines = 0
        tokenLabel.font = .systemFont(ofSize: 14)
        tokenLabel.textColor = .darkGray

        let stackView = UIStackView(arrangedSubviews: [instructionsLabel, tokenLabel])
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(stackView)

        NSLayoutConstraint.activate([
            stackView.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20)
        ])
    }

    func configure(with token: String) {
        self.resetToken = token
        // If the view is already loaded, update the UI immediately
        if isViewLoaded {
            displayToken()
        }
    }

    private func displayToken() {
        if let token = resetToken {
            tokenLabel.text = "Received Token: \(token)"
            // In a real app, you would use this token to make an API call
            // and show password input fields.
        } else {
            tokenLabel.text = "No reset token found."
        }
    }
}